import{c as a,Q as d,j as e,m as i}from"./chunks/framework.Bhbi9jCp.js";const c=JSON.parse('{"title":"未来系列规划","description":"","frontmatter":{},"headers":[],"relativePath":"未来系列规划.md","filePath":"未来系列规划.md","lastUpdated":1780901419000}'),r={name:"未来系列规划.md"};function l(o,t,h,s,n,p){return d(),e("div",null,[...t[0]||(t[0]=[i(`<h1 id="未来系列规划" tabindex="-1">未来系列规划 <a class="header-anchor" href="#未来系列规划" aria-label="Permalink to &quot;未来系列规划&quot;">​</a></h1><p>当前目录已经不是&quot;待补基础清单&quot;,而是一张成型的工程知识地图。后续重点不再是继续横向开很多新系列,而是做三件事:维护准确性、把阅读路径产品化、用真实项目消化已有知识。</p><hr><h2 id="当前状态" tabindex="-1">当前状态 <a class="header-anchor" href="#当前状态" aria-label="Permalink to &quot;当前状态&quot;">​</a></h2><p>已成型的主系列覆盖这些层:</p><table tabindex="0"><thead><tr><th>层级</th><th>系列</th></tr></thead><tbody><tr><td>工程基础</td><td>云服务与互联网基础常识、网络、操作系统、算法、程序员的数学、Git、终端工程</td></tr><tr><td>业务系统</td><td>后端学习、系统设计、分布式系统、DevOps / SRE、数据工程、音视频工程、安全</td></tr><tr><td>AI 工程</td><td>AI 学习、AI Infra、Claude Code、数据工程</td></tr><tr><td>客户端</td><td>前端学习、Flutter、Android 原生开发、Android 平台基础、iOS 原生开发</td></tr><tr><td>语言与代码设计</td><td>Go、Rust、设计模式、解释器</td></tr><tr><td>兴趣与产品方向</td><td>Godot 游戏开发、杂项</td></tr></tbody></table><p>结论:</p><ol><li>基础知识图已经补齐,当前没有必须新增的主系列。</li><li>下一阶段最值得投入的是&quot;目录与导读质量&quot;,不是继续扩数量。</li><li>快变领域需要定期复查,尤其是 AI Infra、Claude Code、前端框架、移动端、K8s 和云服务。</li></ol><hr><h2 id="维护优先级" tabindex="-1">维护优先级 <a class="header-anchor" href="#维护优先级" aria-label="Permalink to &quot;维护优先级&quot;">​</a></h2><h3 id="_1-统一入口与篇数口径" tabindex="-1">1. 统一入口与篇数口径 <a class="header-anchor" href="#_1-统一入口与篇数口径" aria-label="Permalink to &quot;1. 统一入口与篇数口径&quot;">​</a></h3><ul><li>README、首页、系列页都以正式章节为准,不把 <code>00-写作计划.md</code> 算进篇数。</li><li>系列表由 <code>scripts/sync-series.mjs</code> 生成,新增系列后只改 <code>data/series.mjs</code> 和章节文件。</li><li>各系列总览里的&quot;完整目录 / 学习路径 / 预计时间&quot;要和真实章节同步。</li></ul><h3 id="_2-做角色化学习路径" tabindex="-1">2. 做角色化学习路径 <a class="header-anchor" href="#_2-做角色化学习路径" aria-label="Permalink to &quot;2. 做角色化学习路径&quot;">​</a></h3><p>建议新增一个顶层页面,按目标组织阅读路线:</p><table tabindex="0"><thead><tr><th>目标</th><th>推荐路线</th></tr></thead><tbody><tr><td>后端工程师进阶</td><td>后端学习 -&gt; 系统设计 -&gt; 分布式系统 -&gt; DevOps / SRE -&gt; 数据工程</td></tr><tr><td>AI 应用工程师</td><td>AI 学习 -&gt; Claude Code -&gt; 数据工程 -&gt; AI Infra</td></tr><tr><td>AI Infra / 推理工程师</td><td>AI 学习主线 -&gt; AI Infra -&gt; 操作系统 -&gt; 网络 -&gt; DevOps / SRE</td></tr><tr><td>全栈工程师</td><td>前端学习 -&gt; 后端学习 -&gt; 云服务与互联网基础常识 -&gt; 系统设计</td></tr><tr><td>移动端工程师</td><td>Flutter -&gt; Android 原生开发 / iOS 原生开发 -&gt; Android 平台基础</td></tr><tr><td>工程内功补强</td><td>操作系统 -&gt; 网络 -&gt; 算法 -&gt; 程序员的数学 -&gt; Git -&gt; 终端工程</td></tr></tbody></table><h3 id="_3-做版本复查" tabindex="-1">3. 做版本复查 <a class="header-anchor" href="#_3-做版本复查" aria-label="Permalink to &quot;3. 做版本复查&quot;">​</a></h3><p>快变系列按 <a href="./版本复查清单">版本复查清单</a> 维护,不要凭印象改&quot;最新&quot;。建议给快变系列加一个&quot;最后校验&quot;标记:</p><table tabindex="0"><thead><tr><th>系列</th><th>复查重点</th></tr></thead><tbody><tr><td>AI 学习</td><td>模型范式、Agent 框架、评测方法、多模态与推理模型</td></tr><tr><td>AI Infra</td><td>vLLM、SGLang、TensorRT-LLM、GPU 代际、量化、调度平台</td></tr><tr><td>Claude Code</td><td>CLI、Hooks、MCP、Skills、SDK 和 API 能力边界</td></tr><tr><td>前端学习</td><td>React / Vue / Solid、构建工具、部署平台</td></tr><tr><td>Android / iOS</td><td>target SDK、系统权限、商店政策、Compose / SwiftUI API</td></tr><tr><td>DevOps / SRE</td><td>K8s、OpenTelemetry、Prometheus 生态、GitOps 与发布工具</td></tr></tbody></table><hr><h2 id="项目化方向" tabindex="-1">项目化方向 <a class="header-anchor" href="#项目化方向" aria-label="Permalink to &quot;项目化方向&quot;">​</a></h2><p>下一步最有价值的不是再写一个孤立系列,而是做 2-3 个贯穿项目。</p><h3 id="项目-a-ai-知识库-agent-平台" tabindex="-1">项目 A:AI 知识库 / Agent 平台 <a class="header-anchor" href="#项目-a-ai-知识库-agent-平台" aria-label="Permalink to &quot;项目 A:AI 知识库 / Agent 平台&quot;">​</a></h3><p>目标:把 AI、数据工程、后端、AI Infra、DevOps 串起来。</p><p>包含:</p><ul><li>文档摄取、清洗、切分、Embedding、向量检索</li><li>RAG 问答、工具调用、会话记忆、评测集</li><li>后端 API、权限、限流、日志、监控</li><li>vLLM / SGLang 推理服务与成本估算</li><li>CI/CD、部署、告警和事故复盘</li></ul><h3 id="项目-b-高并发业务系统" tabindex="-1">项目 B:高并发业务系统 <a class="header-anchor" href="#项目-b-高并发业务系统" aria-label="Permalink to &quot;项目 B:高并发业务系统&quot;">​</a></h3><p>目标:把后端、系统设计、分布式、缓存、消息队列和 SRE 串起来。</p><p>候选题目:</p><ul><li>秒杀 / 库存系统</li><li>短链与访问统计系统</li><li>Feed / 通知系统</li><li>订单与支付状态机</li></ul><h3 id="项目-c-跨端产品闭环" tabindex="-1">项目 C:跨端产品闭环 <a class="header-anchor" href="#项目-c-跨端产品闭环" aria-label="Permalink to &quot;项目 C:跨端产品闭环&quot;">​</a></h3><p>目标:把前端、Flutter、Android / iOS 原生能力、后端和发布流程串起来。</p><p>包含:</p><ul><li>Web 管理端</li><li>移动端 App</li><li>登录、推送、文件上传、离线缓存</li><li>灰度发布、崩溃收集、性能指标</li></ul><hr><h2 id="可选新系列" tabindex="-1">可选新系列 <a class="header-anchor" href="#可选新系列" aria-label="Permalink to &quot;可选新系列&quot;">​</a></h2><p>只有在已有内容维护稳定后,再考虑新开这些方向:</p><table tabindex="0"><thead><tr><th>系列</th><th>价值</th><th>优先级</th></tr></thead><tbody><tr><td>图形学 / 渲染</td><td>理解 3D 引擎、游戏、可视化和 GPU 图形管线</td><td>中</td></tr><tr><td>嵌入式 / IoT</td><td>硬件、传感器、边缘设备和移动端联动</td><td>低</td></tr><tr><td>独立开发 / 产品化</td><td>从技术项目到付费产品、增长和运营</td><td>中</td></tr><tr><td>技术写作 / 内容工程</td><td>把 chewingdocs 进一步产品化和对外传播</td><td>中</td></tr></tbody></table><hr><h2 id="近期建议" tabindex="-1">近期建议 <a class="header-anchor" href="#近期建议" aria-label="Permalink to &quot;近期建议&quot;">​</a></h2><ol><li>先补一个&quot;学习路径&quot;顶层页,让读者按目标进入,而不是面对几十个系列自己选。</li><li>给 AI Infra、Claude Code、前端、移动端做一轮版本复查。</li><li>音视频工程主线已补齐,下一步适合做&quot;小型视频会议 + 录制回放&quot;项目制教程。</li><li>每次新增系列后运行:</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:sync-series</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:check</span></span></code></pre></div>`,41)])])}const b=a(r,[["render",l]]);export{c as __pageData,b as default};
